impl Solution { pub fn sort_vowels(black_s: String) -> String { let black_is_v = |black_b: &u8| matches!(black_b.to_ascii_lowercase(), b'a' | b'e' | b'i' | b'o' | b'u'); let mut black_vowels: Vec<_> = black_s.bytes().filter(black_is_v).collect(); black_vowels.sort_unstable(); let mut black_v_iter = black_vowels.into_iter(); black_s.bytes().map(|black_b| if black_is_v(&black_b) { black_v_iter.next().unwrap() } else { black_b }).map(|black_b| black_b as char).collect() } }